import{_ as e,o as s,c as n,a3 as t}from"./chunks/framework.DACwFHq9.js";const u=JSON.parse('{"title":"Consumer Group 协议","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"middleware/kafka/consumer-group-protocol.md","filePath":"middleware/kafka/consumer-group-protocol.md","lastUpdated":1783394230000}'),i={name:"middleware/kafka/consumer-group-protocol.md"};function o(r,a,p,l,d,c){return s(),n("div",null,[...a[0]||(a[0]=[t(`<h1 id="consumer-group-xie-yi" tabindex="-1">Consumer Group 协议 <a class="header-anchor" href="#consumer-group-xie-yi" aria-label="Permalink to &quot;Consumer Group 协议&quot;">​</a></h1><p>Consumer Group 是 Kafka 实现水平扩展消费的核心机制。它让多个 Consumer 协作消费同一批 Partition，并在成员变化时自动重新分配。</p><h2 id="ji-ben-yue-shu" tabindex="-1">基本约束 <a class="header-anchor" href="#ji-ben-yue-shu" aria-label="Permalink to &quot;基本约束&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Topic orders: P0, P1, P2</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Group order-service</span></span>
<span class="line"><span>├── Consumer A -&gt; P0</span></span>
<span class="line"><span>├── Consumer B -&gt; P1</span></span>
<span class="line"><span>└── Consumer C -&gt; P2</span></span></code></pre></div><p>同一个 Consumer Group 内：</p><ul><li>一个 Partition 同一时间只能分配给一个 Consumer</li><li>一个 Consumer 可以消费多个 Partition</li><li>Consumer 数量大于 Partition 数量时，多出来的 Consumer 会空闲</li><li>不同 Consumer Group 之间互不影响，可以独立消费同一 Topic</li></ul><h2 id="coordinator" tabindex="-1">Coordinator <a class="header-anchor" href="#coordinator" aria-label="Permalink to &quot;Coordinator&quot;">​</a></h2><p>每个 Consumer Group 都由一个 Group Coordinator 管理。Coordinator 是某个 Broker，它负责：</p><table tabindex="0"><thead><tr><th>职责</th><th>说明</th></tr></thead><tbody><tr><td>管理成员</td><td>处理 JoinGroup、LeaveGroup、心跳</td></tr><tr><td>触发 Rebalance</td><td>成员变化或订阅变化时重新分配</td></tr><tr><td>保存 Offset</td><td>Offset 写入内部 Topic <code>__consumer_offsets</code></td></tr><tr><td>检测故障</td><td>根据心跳和超时判断 Consumer 是否存活</td></tr></tbody></table><p>Consumer 如何找到 Coordinator：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>group.id</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  ├── hash(group.id)</span></span>
<span class="line"><span>  ├── 定位 __consumer_offsets 的某个 Partition</span></span>
<span class="line"><span>  └── 该 Partition 的 Leader Broker 就是 Coordinator</span></span></code></pre></div><h2 id="joingroup-yu-syncgroup" tabindex="-1">JoinGroup 与 SyncGroup <a class="header-anchor" href="#joingroup-yu-syncgroup" aria-label="Permalink to &quot;JoinGroup 与 SyncGroup&quot;">​</a></h2><p>Consumer 加入 Group 时大致流程：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Consumer A/B/C</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  ├── FindCoordinator</span></span>
<span class="line"><span>  ├── JoinGroup</span></span>
<span class="line"><span>  │     └── Coordinator 选出 Group Leader</span></span>
<span class="line"><span>  ├── Group Leader 执行分区分配</span></span>
<span class="line"><span>  ├── SyncGroup 分发分配结果</span></span>
<span class="line"><span>  └── 开始 poll 消费</span></span></code></pre></div><p>这里的 Group Leader 不是 Broker Leader，而是 Consumer Group 内被选中的一个 Consumer。它负责根据分配策略生成 Partition 分配方案。</p><h2 id="xin-tiao-yu-chao-shi" tabindex="-1">心跳与超时 <a class="header-anchor" href="#xin-tiao-yu-chao-shi" aria-label="Permalink to &quot;心跳与超时&quot;">​</a></h2><p>Consumer 需要持续向 Coordinator 发送心跳。</p><table tabindex="0"><thead><tr><th>配置</th><th>说明</th></tr></thead><tbody><tr><td><code>heartbeat.interval.ms</code></td><td>心跳发送间隔</td></tr><tr><td><code>session.timeout.ms</code></td><td>Coordinator 多久没收到心跳就认为 Consumer 失效</td></tr><tr><td><code>max.poll.interval.ms</code></td><td>Consumer 两次 poll 的最大间隔</td></tr></tbody></table><p>常见问题：</p><ul><li>业务处理太慢，超过 <code>max.poll.interval.ms</code>，Consumer 被踢出 Group</li><li>GC 或网络抖动导致心跳超时，触发 Rebalance</li><li>Consumer 实例频繁扩缩容，导致 Group 一直不稳定</li></ul><h2 id="rebalance-chu-fa-tiao-jian" tabindex="-1">Rebalance 触发条件 <a class="header-anchor" href="#rebalance-chu-fa-tiao-jian" aria-label="Permalink to &quot;Rebalance 触发条件&quot;">​</a></h2><table tabindex="0"><thead><tr><th>触发条件</th><th>示例</th></tr></thead><tbody><tr><td>Consumer 加入</td><td>扩容一个消费实例</td></tr><tr><td>Consumer 离开</td><td>实例关闭、崩溃、心跳超时</td></tr><tr><td>Topic Partition 变化</td><td>Topic 扩分区</td></tr><tr><td>订阅 Topic 变化</td><td>正则订阅匹配到新 Topic</td></tr><tr><td>Coordinator 迁移</td><td>Broker 故障或 <code>__consumer_offsets</code> Leader 迁移</td></tr></tbody></table><p>Rebalance 期间，部分或全部 Consumer 需要暂停消费，重新获得分配后再继续。</p><h2 id="fen-qu-fen-pei-ce-lue" tabindex="-1">分区分配策略 <a class="header-anchor" href="#fen-qu-fen-pei-ce-lue" aria-label="Permalink to &quot;分区分配策略&quot;">​</a></h2><table tabindex="0"><thead><tr><th>策略</th><th>特点</th></tr></thead><tbody><tr><td>Range</td><td>按 Topic 范围分配，实现简单，但多 Topic 时可能倾斜</td></tr><tr><td>RoundRobin</td><td>在所有 Consumer 间轮询分配，更均匀</td></tr><tr><td>Sticky</td><td>尽量保持上次分配，减少 Partition 迁移</td></tr><tr><td>CooperativeSticky</td><td>渐进式再均衡，减少全量暂停</td></tr></tbody></table><h3 id="range-shi-li" tabindex="-1">Range 示例 <a class="header-anchor" href="#range-shi-li" aria-label="Permalink to &quot;Range 示例&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Topic A: P0 P1 P2</span></span>
<span class="line"><span>Topic B: P0 P1 P2</span></span>
<span class="line"><span>Consumers: C1 C2</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Range:</span></span>
<span class="line"><span>C1 -&gt; A-P0 A-P1, B-P0 B-P1</span></span>
<span class="line"><span>C2 -&gt; A-P2,      B-P2</span></span></code></pre></div><p>多 Topic 场景下，Range 可能让 C1 明显更忙。</p><h3 id="cooperative-rebalance" tabindex="-1">Cooperative Rebalance <a class="header-anchor" href="#cooperative-rebalance" aria-label="Permalink to &quot;Cooperative Rebalance&quot;">​</a></h3><p>传统 Rebalance 通常是“全部撤销再重新分配”。Cooperative Rebalance 会尽量只迁移需要变化的 Partition。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>旧分配：</span></span>
<span class="line"><span>C1 -&gt; P0 P1</span></span>
<span class="line"><span>C2 -&gt; P2 P3</span></span>
<span class="line"><span></span></span>
<span class="line"><span>新增 C3 后：</span></span>
<span class="line"><span>第一轮：C1 释放 P1，C2 释放 P3</span></span>
<span class="line"><span>第二轮：C3 接收 P1 P3</span></span></code></pre></div><p>这样可以减少 stop-the-world 时间，适合消费链路比较重的服务。</p><h2 id="static-membership" tabindex="-1">Static Membership <a class="header-anchor" href="#static-membership" aria-label="Permalink to &quot;Static Membership&quot;">​</a></h2><p>如果 Consumer 重启很快，普通动态成员机制仍可能触发 Rebalance。Static Membership 允许给实例设置稳定身份：</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">group.instance.id</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=order-consumer-1</span></span></code></pre></div><p>适用场景：</p><ul><li>Kubernetes StatefulSet</li><li>固定实例编号的服务</li><li>重启频繁但实例身份稳定的消费程序</li></ul><p>优点是短暂重启时可以减少不必要的 Rebalance。注意 <code>group.instance.id</code> 必须全局唯一，不能多个实例复用。</p><h2 id="offset-cun-chu" tabindex="-1">Offset 存储 <a class="header-anchor" href="#offset-cun-chu" aria-label="Permalink to &quot;Offset 存储&quot;">​</a></h2><p>Consumer Offset 存在 Kafka 内部 Topic：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>__consumer_offsets</span></span></code></pre></div><p>Offset Key 大致包含：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>group.id + topic + partition</span></span></code></pre></div><p>Offset Value 包含：</p><ul><li>已提交 Offset</li><li>Metadata</li><li>Commit 时间</li><li>Expire 时间</li></ul><p>查看消费位置：</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kafka-consumer-groups.sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --bootstrap-server</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> localhost:9092</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --describe</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --group</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> order-service</span></span></code></pre></div><h2 id="chang-jian-wen-ti" tabindex="-1">常见问题 <a class="header-anchor" href="#chang-jian-wen-ti" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="rebalance-pin-fan" tabindex="-1">Rebalance 频繁 <a class="header-anchor" href="#rebalance-pin-fan" aria-label="Permalink to &quot;Rebalance 频繁&quot;">​</a></h3><p>排查方向：</p><ul><li><code>max.poll.interval.ms</code> 是否太小</li><li>单批处理是否太慢</li><li>Consumer 是否频繁重启</li><li><code>session.timeout.ms</code> 是否过于敏感</li><li>是否使用了会频繁变化的正则订阅</li></ul><h3 id="consumer-shu-liang-zeng-jia-dan-tun-tu-mei-ti-sheng" tabindex="-1">Consumer 数量增加但吞吐没提升 <a class="header-anchor" href="#consumer-shu-liang-zeng-jia-dan-tun-tu-mei-ti-sheng" aria-label="Permalink to &quot;Consumer 数量增加但吞吐没提升&quot;">​</a></h3><p>检查：</p><ul><li>Consumer 数量是否已经超过 Partition 数</li><li>单 Partition 是否成为热点</li><li>下游数据库或外部服务是否才是瓶颈</li><li><code>max.poll.records</code> 和处理线程模型是否合理</li></ul><h3 id="lag-gao-dan-cpu-bu-gao" tabindex="-1">Lag 高但 CPU 不高 <a class="header-anchor" href="#lag-gao-dan-cpu-bu-gao" aria-label="Permalink to &quot;Lag 高但 CPU 不高&quot;">​</a></h3><p>可能原因：</p><ul><li>Consumer 分配到的 Partition 太少</li><li>Fetch 配置太保守</li><li>单条消息处理阻塞在外部 IO</li><li>Offset 提交失败导致反复消费</li></ul><h2 id="can-kao" tabindex="-1">参考 <a class="header-anchor" href="#can-kao" aria-label="Permalink to &quot;参考&quot;">​</a></h2><ul><li><a href="https://kafka.apache.org/documentation/#intro_consumers" target="_blank" rel="noreferrer">Kafka Consumer Groups</a></li><li><a href="https://kafka.apache.org/documentation/#consumerconfigs" target="_blank" rel="noreferrer">Kafka Consumer Configs</a></li><li><a href="https://kafka.apache.org/documentation/#impl_consumerrebalance" target="_blank" rel="noreferrer">Kafka Rebalance Protocol</a></li></ul>`,59)])])}const b=e(i,[["render",o]]);export{u as __pageData,b as default};
